def _get_first_branch_dimension_value_id(apps):
    """Get first branch DimensionValue id for backfill."""
    GeneralLedgerSetup = apps.get_model("financials", "GeneralLedgerSetup")
    Dimension = apps.get_model("dimension", "Dimension")
    DimensionValue = apps.get_model("dimension", "DimensionValue")
    gl = GeneralLedgerSetup.objects.first()
    dim = None
    if gl and gl.global_dimension_1_id:
        dim = gl.global_dimension_1
    if not dim:
        dim = Dimension.objects.filter(code__iexact="BRANCH").first()
    if not dim:
        return None
    dv = DimensionValue.objects.filter(dimension_code=dim).order_by("code").first()
    return dv.id if dv else None


def _pg_column_exists(cursor, relname, attname):
    cursor.execute(
        """
        SELECT 1
        FROM pg_attribute a
        JOIN pg_class c ON a.attrelid = c.oid
        JOIN pg_namespace n ON c.relnamespace = n.oid
        WHERE n.nspname = current_schema()
          AND c.relname = %s
          AND a.attname = %s
          AND a.attnum > 0
          AND NOT a.attisdropped
        """,
        [relname, attname],
    )
    return cursor.fetchone() is not None


